var timeTaken = function(edges) {
    const n = edges.length + 1;
    const graph = Array.from({ length: n }, () => []);
    for (const [a, b] of edges) {
        graph[a].push(b);
        graph[b].push(a);
    }
    const weight = (v) => (v % 2 === 0 ? 2 : 1);

    const parent = new Array(n).fill(-1);
    const order = [0];
    const visited = new Array(n).fill(false);
    visited[0] = true;
    let qi = 0;
    const queue = [0];
    while (qi < queue.length) {
        const u = queue[qi++];
        for (const v of graph[u]) {
            if (!visited[v]) {
                visited[v] = true;
                parent[v] = u;
                order.push(v);
                queue.push(v);
            }
        }
    }

    const top1Val = new Array(n).fill(0);
    const top1Child = new Array(n).fill(-1);
    const top2Val = new Array(n).fill(0);

    for (let i = order.length - 1; i >= 0; i--) {
        const u = order[i];
        const val = weight(u) + top1Val[u];
        const p = parent[u];
        if (p === -1) continue;
        if (val > top1Val[p]) {
            top2Val[p] = top1Val[p];
            top1Val[p] = val;
            top1Child[p] = u;
        } else if (val > top2Val[p]) {
            top2Val[p] = val;
        }
    }

    const down = top1Val;
    const up = new Array(n).fill(0);
    for (const u of order) {
        const p = parent[u];
        if (p === -1) continue;
        const bestSibling = top1Child[p] === u ? top2Val[p] : top1Val[p];
        const bestExcl = Math.max(up[p], bestSibling);
        up[u] = weight(p) + bestExcl;
    }

    return Array.from({ length: n }, (_, v) => Math.max(down[v], up[v]));
};
